// =====================================================================
// Аналитика для утреннего дайджеста.
// Источники: garmin_daily, gcal_events, fatsecret_daily, nutrition_goals.
// =====================================================================

const garminCsv = $('Тянем Garmin CSV').item.json.data || $('Тянем Garmin CSV').item.json;

let eventsCsv = '';
try { eventsCsv = $('Тянем события').item.json.data || $('Тянем события').item.json || ''; } catch (e) {}

let fsCsv = '';
try { fsCsv = $('Тянем FatSecret').item.json.data || $('Тянем FatSecret').item.json || ''; } catch (e) {}

let goalsCsv = '';
try { goalsCsv = $('Тянем цели КБЖУ').item.json.data || $('Тянем цели КБЖУ').item.json || ''; } catch (e) {}

// ---------- CSV parser ----------
function parseCsv(raw) {
  if (typeof raw !== 'string') raw = String(raw);
  const lines = raw.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];
  const splitLine = (s) => s.match(/("([^"]|"")*"|[^,]*)(,|$)/g)
    .filter(Boolean)
    .map(v => v.replace(/,$/, '').replace(/^"|"$/g, '').replace(/""/g, '"').trim());
  const headers = splitLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = splitLine(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = cells[i] ?? ''; });
    return obj;
  });
}
const rows      = parseCsv(garminCsv).sort((a,b)=>(a.date||'').localeCompare(b.date||''));
const eventRows = parseCsv(eventsCsv);
const fsRows    = parseCsv(fsCsv).sort((a,b)=>(a.date||'').localeCompare(b.date||''));
const goalsRows = parseCsv(goalsCsv).sort((a,b)=>(a.date_set||'').localeCompare(b.date_set||''));

// ---------- helpers ----------
const num = (v) => {
  if (v == null || v === '') return NaN;
  if (typeof v === 'number') return v;
  const cleaned = String(v).replace(/[\s\u00A0]/g,'').replace(',','.');
  const n = parseFloat(cleaned);
  return isFinite(n) ? n : NaN;
};
const avg = (xs) => {
  const ys = xs.map(num).filter(v => isFinite(v));
  if (!ys.length) return null;
  return ys.reduce((a,b)=>a+b,0)/ys.length;
};
const round = (v, d=1) => v == null ? null : Number(v.toFixed(d));

// ---------- Текущая дата (МСК) и история ----------
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Moscow' });
const latest = rows[rows.length - 1] || {};
const last7  = rows.slice(-7);
const prev7  = rows.slice(-14, -7);
const last14 = rows.slice(-14);
const last30 = rows.slice(-30);

const metricKeys = ['sleep_hours','sleep_score','hrv_last_night','steps','stress_avg','body_battery_min'];
const lowerIsBetter = { stress_avg: true };

// ---------- Тренды Garmin ----------
const trends = {};
for (const k of metricKeys) {
  const a7  = avg(last7.map(r=>r[k]));
  const a14 = avg(last14.map(r=>r[k]));
  const a30 = avg(last30.map(r=>r[k]));
  const aPrev7 = avg(prev7.map(r=>r[k]));
  const decimals = (k === 'sleep_hours') ? 1 : 0;
  trends[k] = {
    avg_7d: round(a7, decimals),
    avg_14d: round(a14, decimals),
    avg_30d: round(a30, decimals),
    delta_vs_prev_week_pct: (a7!=null && aPrev7!=null && aPrev7!==0) ? Math.round((a7-aPrev7)/Math.abs(aPrev7)*100) : null,
    delta_7d_vs_30d_pct:    (a7!=null && a30!=null && a30!==0)       ? Math.round((a7-a30)/Math.abs(a30)*100)       : null,
  };
}

function streakWorseThanBaseline(rows, key, baseline, lowerIsBetterFlag) {
  if (baseline == null) return 0;
  let count = 0;
  for (let i = rows.length - 1; i >= 0; i--) {
    const v = num(rows[i][key]);
    if (!isFinite(v)) break;
    const worse = lowerIsBetterFlag ? (v > baseline) : (v < baseline);
    if (worse) count++; else break;
  }
  return count;
}
const streaks = {};
for (const k of metricKeys) {
  streaks[k] = streakWorseThanBaseline(rows, k, trends[k].avg_30d, !!lowerIsBetter[k]);
}

// ---------- События по дням ----------
const eventsByDay = {};
for (const e of eventRows) {
  const startIso = e.start_time || e.date || '';
  const day = (startIso.match(/^(\d{4}-\d{2}-\d{2})/) || [])[1] || '';
  if (!day) continue;
  const tm = startIso.match(/T(\d{2}):(\d{2})/);
  const hour = tm ? parseInt(tm[1], 10) : null;
  (eventsByDay[day] ||= []).push({
    title: e.event_title || '',
    time: tm ? `${tm[1]}:${tm[2]}` : '—',
    hour,
    is_evening: hour != null && hour >= 18,
    is_late:    hour != null && hour >= 21,
  });
}

// ---------- FatSecret: индекс по дате + тренды ----------
const fsByDate = {};
for (const r of fsRows) if (r.date) fsByDate[r.date] = r;
const fsLast7  = fsRows.slice(-7);
const fsPrev7  = fsRows.slice(-14, -7);
const fsLast30 = fsRows.slice(-30);
const fsKeys = ['calories_kcal','protein_g','fat_g','carbs_g'];
const fsTrends = {};
for (const k of fsKeys) {
  const a7  = avg(fsLast7.map(r=>r[k]));
  const a30 = avg(fsLast30.map(r=>r[k]));
  const aPrev7 = avg(fsPrev7.map(r=>r[k]));
  fsTrends[k] = {
    avg_7d: round(a7, 0),
    avg_30d: round(a30, 0),
    delta_vs_prev_week_pct: (a7!=null && aPrev7!=null && aPrev7!==0) ? Math.round((a7-aPrev7)/Math.abs(aPrev7)*100) : null,
    delta_7d_vs_30d_pct:    (a7!=null && a30!=null && a30!==0)       ? Math.round((a7-a30)/Math.abs(a30)*100)       : null,
  };
}

// ---------- Цель КБЖУ: берём самую свежую запись ----------
const latestGoal = goalsRows[goalsRows.length - 1] || null;
const goal = latestGoal ? {
  date_set:  latestGoal.date_set || null,
  kcal:      num(latestGoal.kcal)      || null,
  protein_g: num(latestGoal.protein_g) || null,
  fat_g:     num(latestGoal.fat_g)     || null,
  carbs_g:   num(latestGoal.carbs_g)   || null,
  source:    latestGoal.source || null,
} : null;

// Streak'и в FS — подряд дней в норме (между warn=±25% и good=±10% от цели).
// Считаем по каждому из ккал/Б/Ж/У отдельно. "в норме" = abs(delta_pct) <= 15.
function nutritionStreak(rows, key, target) {
  if (!target) return 0;
  let count = 0;
  for (let i = rows.length - 1; i >= 0; i--) {
    const v = num(rows[i][key]);
    if (!isFinite(v)) break;
    const delta = Math.abs(v - target) / target * 100;
    if (delta <= 15) count++; else break;
  }
  return count;
}
const nutritionStreaks = goal ? {
  calories_kcal: nutritionStreak(fsRows, 'calories_kcal', goal.kcal),
  protein_g:     nutritionStreak(fsRows, 'protein_g',     goal.protein_g),
  fat_g:         nutritionStreak(fsRows, 'fat_g',         goal.fat_g),
  carbs_g:       nutritionStreak(fsRows, 'carbs_g',       goal.carbs_g),
} : null;

// Питание за вчера + дельта к цели в %
const fsYesterday = fsByDate[latest.date] || null;
const nutritionYesterday = fsYesterday ? {
  date: fsYesterday.date,
  calories_kcal: round(num(fsYesterday.calories_kcal), 0),
  protein_g:     round(num(fsYesterday.protein_g),     0),
  fat_g:         round(num(fsYesterday.fat_g),         0),
  carbs_g:       round(num(fsYesterday.carbs_g),       0),
  fiber_g:       round(num(fsYesterday.fiber_g),       0),
  entries_count: num(fsYesterday.entries_count) || 0,
  vs_goal_pct: goal ? {
    calories_kcal: goal.kcal      ? Math.round((num(fsYesterday.calories_kcal) - goal.kcal)      / goal.kcal      * 100) : null,
    protein_g:     goal.protein_g ? Math.round((num(fsYesterday.protein_g)     - goal.protein_g) / goal.protein_g * 100) : null,
    fat_g:         goal.fat_g     ? Math.round((num(fsYesterday.fat_g)         - goal.fat_g)     / goal.fat_g     * 100) : null,
    carbs_g:       goal.carbs_g   ? Math.round((num(fsYesterday.carbs_g)       - goal.carbs_g)   / goal.carbs_g   * 100) : null,
  } : null,
} : null;

// ---------- daily_last_7: контекст за 7 дней (Garmin + события + питание) ----------
const dailyContext = last7.map(r => {
  const d = r.date;
  const evs = eventsByDay[d] || [];
  const fs  = fsByDate[d] || {};
  return {
    date: d,
    sleep_hours: round(num(r.sleep_hours), 1),
    sleep_score: num(r.sleep_score) || null,
    hrv:    num(r.hrv_last_night) || null,
    stress: num(r.stress_avg)     || null,
    steps:  num(r.steps)          || null,
    body_battery_min: num(r.body_battery_min) || null,
    events_total:   evs.length,
    events_evening: evs.filter(e => e.is_evening).length,
    events_late:    evs.filter(e => e.is_late).length,
    kcal:    num(fs.calories_kcal) || null,
    protein: num(fs.protein_g)     || null,
    fat:     num(fs.fat_g)         || null,
    carbs:   num(fs.carbs_g)       || null,
  };
});

// ---------- События на сегодня ----------
const todayEvents = (eventsByDay[today] || [])
  .sort((a,b) => a.time.localeCompare(b.time))
  .slice(0, 6)
  .map(e => ({ title: e.title, time: e.time }));

// ---------- Финальный payload ----------
const payload = {
  today,
  yesterday: {
    date: latest.date || null,
    sleep_hours: round(num(latest.sleep_hours), 1),
    sleep_score: num(latest.sleep_score) || null,
    hrv:    num(latest.hrv_last_night) || null,
    steps:  num(latest.steps)          || null,
    stress: num(latest.stress_avg)     || null,
    body_battery_max: num(latest.body_battery_max) || null,
    body_battery_min: num(latest.body_battery_min) || null,
    events_total:   (eventsByDay[latest.date] || []).length,
    events_evening: (eventsByDay[latest.date] || []).filter(e => e.is_evening).length,
    events_late:    (eventsByDay[latest.date] || []).filter(e => e.is_late).length,
  },
  trends,
  streaks,
  nutrition_yesterday: nutritionYesterday,
  nutrition_goal: goal,
  nutrition_trends: fsTrends,
  nutrition_streaks: nutritionStreaks,
  daily_last_7: dailyContext,
  events_today: todayEvents,
  events_in_sheet_total: eventRows.length,
  fs_in_sheet_total: fsRows.length,
  dashboard_url: $('Конфиг').item.json.dashboard_url,
};

return [{ json: payload }];
